/**
 * SafetyPro AI — fix_global_scroll.js
 * Applies uniform scrollbar + layout fix to ALL HTML pages
 * Run: cd C:\safetypro_complete_frontend && node fix_global_scroll.js
 */
const fs=require('fs'),path=require('path'),zlib=require('zlib'),glob=require('fs');

const DIR=process.cwd();
const files=fs.readdirSync(DIR).filter(f=>f.endsWith('.html')&&!f.includes('_bk_')&&!f.includes('_backup'));

console.log('HTML files found:',files.length);
files.forEach(f=>console.log(' ',f));

/* Global CSS to inject into every page */
const GLOBAL_CSS=zlib.gunzipSync(Buffer.from('','base64')).toString('utf8');
const MARKER='/* === SafetyPro Global === */';

/* Conflicting rules to remove from each page */
const BAD_RULES=[
  '.content{overflow:visible !important;height:auto !important;}',
  '.content{overflow:visible;height:auto;}',
];

let patched=0;
files.forEach(function(filename){
  const filepath=path.join(DIR,filename);
  let html=fs.readFileSync(filepath,'utf8');
  
  /* Skip if already patched */
  if(html.includes(MARKER)){
    console.log('SKIP (already patched):',filename);
    return;
  }
  
  /* Remove conflicting rules */
  BAD_RULES.forEach(function(rule){
    if(html.includes(rule))html=html.replace(rule,'/* removed-global */');
  });
  
  /* Inject global CSS at top of first <style> block */
  const styleIdx=html.indexOf('<style>');
  if(styleIdx>0){
    html=html.slice(0,styleIdx)+'<style>\n'+MARKER+'\n'+GLOBAL_CSS+'\n'+html.slice(styleIdx+7);
    const bk=filepath.replace('.html','_bk_gfix_'+Date.now()+'.html');
    fs.copyFileSync(filepath,bk);
    fs.writeFileSync(filepath,html,'utf8');
    console.log('PATCHED:',filename,'('+Math.round(html.length/1024)+'KB)');
    patched++;
  }else{
    console.log('SKIP (no style tag):',filename);
  }
});

console.log('');
console.log('Patched:',patched,'files');
console.log('');

/* Also write the fixed audit_compliance file */
const AC_FILE=path.join(DIR,'safetypro_audit_compliance.html');
const acHtml=zlib.gunzipSync(Buffer.from('','base64')).toString('utf8');
fs.writeFileSync(AC_FILE,acHtml,'utf8');
console.log('safetypro_audit_compliance.html updated:',Math.round(acHtml.length/1024),'KB');

/* Write global CSS as standalone file too */
fs.writeFileSync(path.join(DIR,'safetypro_global.css'),GLOBAL_CSS,'utf8');
console.log('safetypro_global.css written');

console.log('');
console.log('Deploy: npx wrangler pages deploy . --project-name safetypro-frontend');
